<?php
declare(strict_types=1);require __DIR__.'/bootstrap.php';$token=vp3_input('token');$error='';$complete=false;if(vp3_method()==='POST'){vp3_verify_csrf();$token=(string)($_POST['token']??'');$password=(string)($_POST['password']??'');if(strlen($password)<12){$error='Use a password of at least 12 characters.';}elseif($token===''||!vp3_db_available()){$error='The reset request is invalid.';}else{$complete=vp3_transaction(function(PDO $pdo)use($token,$password):bool{$stmt=$pdo->prepare('SELECT id,customer_id FROM password_resets WHERE token_hash=? AND used_at IS NULL AND expires_at>NOW() LIMIT 1 FOR UPDATE');$stmt->execute([vp3_hash_token($token)]);$row=$stmt->fetch();if(!is_array($row))return false;$pdo->prepare('UPDATE customers SET password_hash=?,updated_at=NOW() WHERE id=?')->execute([password_hash($password,PASSWORD_DEFAULT),(int)$row['customer_id']]);$pdo->prepare('UPDATE password_resets SET used_at=NOW() WHERE id=?')->execute([(int)$row['id']]);$pdo->prepare('UPDATE password_resets SET used_at=NOW() WHERE customer_id=? AND used_at IS NULL')->execute([(int)$row['customer_id']]);vp3_audit('customer',(int)$row['customer_id'],'customer.password_reset_completed','customer',(string)$row['customer_id']);return true;});if(!$complete)$error='The reset link is invalid or expired.';}}$pageTitle='Reset Password';require VP3_ROOT.'/includes/header.php';?><section class="form-shell"><span class="eyebrow">Account recovery</span><h1><?=$complete?'Password updated.':'Choose a new password.'?></h1><?php if($complete):?><a class="button" href="login.php">Sign in</a><?php else:?><?php if($error):?><div class="flash error"><?=vp3_e($error)?></div><?php endif;?><form method="post"><?=vp3_csrf_field()?><input type="hidden" name="token" value="<?=vp3_e($token)?>"><div class="field"><label for="password">New password</label><input id="password" name="password" type="password" minlength="12" required autocomplete="new-password"></div><button class="button">Update password</button></form><?php endif;?></section><?php require VP3_ROOT.'/includes/footer.php';?>
